209→class MyData
210→
211→// declare thread local variable holding MyData
212→private val myThreadLocal = ThreadLocal<MyData?>()
213→
214→// declare context element holding MyData
215→class MyElement(val data: MyData) : ThreadContextElement<MyData?> {
216→    // declare companion object for a key of this element in coroutine context
217→    companion object Key : CoroutineContext.Key<MyElement>
218→
219→    // provide the key of the corresponding context element
220→    override val key: CoroutineContext.Key<MyElement>
221→        get() = Key
222→
223→    // this is invoked before coroutine is resumed on current thread
224→    override fun updateThreadContext(context: CoroutineContext): MyData? {
225→        val oldState = myThreadLocal.get()
226→        myThreadLocal.set(data)
227→        return oldState
228→    }
229→
230→    // this is invoked after coroutine has suspended on current thread
231→    override fun restoreThreadContext(context: CoroutineContext, oldState: MyData?) {
232→        myThreadLocal.set(oldState)
233→    }
234→}
235→
236→/**
237→ * A [ThreadContextElement] that implements copy semantics in [copyForChild].
238→ */
239→class CopyForChildCoroutineElement(val data: MyData?) : CopyableThreadContextElement<MyData?> {
240→    companion object Key : CoroutineContext.Key<CopyForChildCoroutineElement>
241→
242→    override val key: CoroutineContext.Key<CopyForChildCoroutineElement>
243→        get() = Key
244→
245→    override fun updateThreadContext(context: CoroutineContext): MyData? {
246→        val oldState = myThreadLocal.get()
247→        myThreadLocal.set(data)
248→        return oldState
249→    }
250→
251→    override fun mergeForChild(overwritingElement: CoroutineContext.Element): CopyForChildCoroutineElement {
252→        TODO("Not used in tests")
253→    }
254→
255→    override fun restoreThreadContext(context: CoroutineContext, oldState: MyData?) {
256→        myThreadLocal.set(oldState)
257→    }
258→
259→    /**
260→     * At coroutine launch time, the _current value of the ThreadLocal_ is inherited by the new
261→     * child coroutine, and that value is copied to a new, unique, ThreadContextElement memory
262→     * reference for the child coroutine to use uniquely.
263→     *
264→     * n.b. the value copied to the child must be the __current value of the ThreadLocal__ and not
265→     * the value initially passed to the ThreadContextElement in order to reflect writes made to the
266→     * ThreadLocal between coroutine resumption and the child coroutine launch point. Those writes
267→     * will be reflected in the parent coroutine's [CopyForChildCoroutineElement] when it yields the
268→     * thread and calls [restoreThreadContext].
269→     */
270→    override fun copyForChild(): CopyForChildCoroutineElement {
271→        return CopyForChildCoroutineElement(myThreadLocal.get())
272→    }
273→}
274→
275→
276→/**
277→ * Calls [block], setting the value of [this] [ThreadLocal] for the duration of [block].
278→ *
279→ * When a [CopyForChildCoroutineElement] for `this` [ThreadLocal] is used within a
280→ * [CoroutineContext], a ThreadLocal set this way will have the "correct" value expected lexically
281→ * at every statement reached, whether that statement is reached immediately, across suspend and
282→ * redispatch within one coroutine, or within a child coroutine. Writes made to the `ThreadLocal`
283→ * by child coroutines will not be visible to the parent coroutine. Writes made to the `ThreadLocal`
284→ * by the parent coroutine _after_ launching a child coroutine will not be visible to that child
285→ * coroutine.
286→ */
287→private inline fun <ThreadLocalT, OutputT> ThreadLocal<ThreadLocalT>.setForBlock(
288→    value: ThreadLocalT,
289→    crossinline block: () -> OutputT
290→) {
291→    val priorValue = get()
292→    set(value)
293→    block()
294→    set(priorValue)
295→}
