    override fun dispatchYield(context: CoroutineContext, block: Runnable) {
        // 
        // `yield()` is supposed to give already-resumable coroutines a chance to run.
        // For [EventLoop], delayed resumption tasks live in a separate heap and are moved into
        // the main FIFO queue only during [processNextEvent].
        //
        // Without this extra step, a `yield()` continuation can end up in the FIFO queue *ahead* of
        // already-due delayed tasks, causing `yield()` to resume immediately.
        //
        val delayed = _delayed.value
        if (delayed != null && !delayed.isEmpty) {
            val now = nanoTime()
            // If the earliest delayed task is due, move due delayed tasks to the main queue first.
            if (delayed.peek()?.timeToExecute(now) == true) {
                enqueueDelayedTasks(delayed, now)
            }
        }
        enqueue(block)
    }

    private fun enqueueDelayedTasks(delayed: DelayedTaskQueue, now: Long) {
        while (true) {
