import kotlinx.coroutines.testing.*
import org.junit.Test
import kotlin.test.*

class EventLoopYieldAfterDelayTest : TestBase() {

    @Test
    fun testYieldProcessesAlreadyDueDelayedTasksFirst() = runBlocking {
        val events = ArrayList<String>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            delay(1)
            events += "first"
        }

        // Block the event-loop thread long enough for the delay to expire,
        // so the delayed continuation is ready but still sits in the delayed heap.
        Thread.sleep(50)

        yield()
        events += "second"

        job.join()
        assertEquals(listOf("first", "second"), events)
    }
}
